You are working in /tmp/sv-1033764e16f649b7b443c09966acfd86/ShipmentTracker which contains a Blazor Web App solution with two projects:
- ShipmentTracker (server project) at ShipmentTracker/ShipmentTracker/
- ShipmentTracker.Client (WASM client project) at ShipmentTracker/ShipmentTracker.Client/

The app uses Auto render mode (Interactive Server + WebAssembly), Individual authentication with ASP.NET Identity (SQLite), and .NET 11 preview.

I need you to build a logistics shipment tracking application with these features:

## 1. Shared Models
Create a file `ShipmentTracker/ShipmentTracker.Client/Models/Shipment.cs` with:
```csharp
namespace ShipmentTracker.Client.Models;

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime ShippedDate { get; set; }
    public DateTime EstimatedDelivery { get; set; }
    public string CustomerEmail { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public enum ShipmentStatus
{
    Pending,
    InTransit,
    OutForDelivery,
    Delivered,
    Delayed
}
```

## 2. Server-side: Entity, DbContext update, API endpoints

### Update ApplicationDbContext
The file is at `ShipmentTracker/ShipmentTracker/Data/ApplicationDbContext.cs`. Add a DbSet<ShipmentEntity> to it. Create a ShipmentEntity class in `ShipmentTracker/ShipmentTracker/Data/ShipmentEntity.cs`:
```csharp
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Data;

public class ShipmentEntity
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime ShippedDate { get; set; }
    public DateTime EstimatedDelivery { get; set; }
    public string CustomerEmail { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}
```

### Add API Endpoints
In Program.cs (server), after `app.MapAdditionalIdentityEndpoints();`, add minimal API endpoints:

```csharp
// Shipment API endpoints
app.MapGet("/api/shipments", async (ApplicationDbContext db, HttpContext http) =>
{
    var user = await http.GetIdentityUser(db);
    if (user == null) return Results.Unauthorized();

    var shipments = await db.Shipments
        .Select(s => new Shipment
        {
            Id = s.Id,
            TrackingNumber = s.TrackingNumber,
            Origin = s.Origin,
            Destination = s.Destination,
            Status = s.Status,
            ShippedDate = s.ShippedDate,
            EstimatedDelivery = s.EstimatedDelivery,
            CustomerEmail = s.CustomerEmail,
            Description = s.Description
        })
        .ToListAsync();
    return Results.Ok(shipments);
}).RequireAuthorization();

app.MapGet("/api/shipments/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
{
    var shipment = await db.Shipments
        .Where(s => s.TrackingNumber == trackingNumber)
        .Select(s => new Shipment
        {
            Id = s.Id,
            TrackingNumber = s.TrackingNumber,
            Origin = s.Origin,
            Destination = s.Destination,
            Status = s.Status,
            ShippedDate = s.ShippedDate,
            EstimatedDelivery = s.EstimatedDelivery,
            CustomerEmail = s.CustomerEmail,
            Description = s.Description
        })
        .FirstOrDefaultAsync();
    return shipment is not null ? Results.Ok(shipment) : Results.NotFound();
}).RequireAuthorization();

app.MapPost("/api/shipments", async (Shipment shipment, ApplicationDbContext db) =>
{
    var entity = new ShipmentEntity
    {
        TrackingNumber = shipment.TrackingNumber,
        Origin = shipment.Origin,
        Destination = shipment.Destination,
        Status = shipment.Status,
        ShippedDate = shipment.ShippedDate,
        EstimatedDelivery = shipment.EstimatedDelivery,
        CustomerEmail = shipment.CustomerEmail,
        Description = shipment.Description
    };
    db.Shipments.Add(entity);
    await db.SaveChangesAsync();
    shipment.Id = entity.Id;
    return Results.Created($"/api/shipments/{entity.Id}", shipment);
}).RequireAuthorization();

app.MapPut("/api/shipments/{id}", async (int id, Shipment shipment, ApplicationDbContext db) =>
{
    var entity = await db.Shipments.FindAsync(id);
    if (entity is null) return Results.NotFound();
    entity.Status = shipment.Status;
    entity.Destination = shipment.Destination;
    entity.EstimatedDelivery = shipment.EstimatedDelivery;
    entity.Description = shipment.Description;
    await db.SaveChangesAsync();
    return Results.Ok();
}).RequireAuthorization();
```

Actually, let's simplify. Don't use a helper method. Just use `RequireAuthorization()` on the endpoints. The user info we won't filter by—dispatchers see all.

### Seed data
Add a data seeder. After `var app = builder.Build();` add:
```csharp
// Seed database
using (var scope = app.Services.CreateScope())
{
    var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
    db.Database.Migrate();
    if (!db.Shipments.Any())
    {
        db.Shipments.AddRange(
            new ShipmentEntity { TrackingNumber = "TRK-001234", Origin = "New York, NY", Destination = "Los Angeles, CA", Status = ShipmentStatus.InTransit, ShippedDate = DateTime.UtcNow.AddDays(-2), EstimatedDelivery = DateTime.UtcNow.AddDays(3), CustomerEmail = "alice@example.com", Description = "Electronics - Laptop" },
            new ShipmentEntity { TrackingNumber = "TRK-005678", Origin = "Chicago, IL", Destination = "Miami, FL", Status = ShipmentStatus.OutForDelivery, ShippedDate = DateTime.UtcNow.AddDays(-4), EstimatedDelivery = DateTime.UtcNow, CustomerEmail = "bob@example.com", Description = "Furniture - Office Chair" },
            new ShipmentEntity { TrackingNumber = "TRK-009012", Origin = "Seattle, WA", Destination = "Denver, CO", Status = ShipmentStatus.Pending, ShippedDate = DateTime.UtcNow, EstimatedDelivery = DateTime.UtcNow.AddDays(5), CustomerEmail = "carol@example.com", Description = "Medical Supplies" },
            new ShipmentEntity { TrackingNumber = "TRK-003456", Origin = "Boston, MA", Destination = "Houston, TX", Status = ShipmentStatus.Delivered, ShippedDate = DateTime.UtcNow.AddDays(-7), EstimatedDelivery = DateTime.UtcNow.AddDays(-1), CustomerEmail = "dave@example.com", Description = "Auto Parts" },
            new ShipmentEntity { TrackingNumber = "TRK-007890", Origin = "San Francisco, CA", Destination = "Phoenix, AZ", Status = ShipmentStatus.Delayed, ShippedDate = DateTime.UtcNow.AddDays(-3), EstimatedDelivery = DateTime.UtcNow.AddDays(2), CustomerEmail = "eve@example.com", Description = "Perishable Goods - Seafood" }
        );
        db.SaveChanges();
    }
}
```

## 3. Client-side service
Create `ShipmentTracker/ShipmentTracker.Client/Services/ShipmentService.cs`:
```csharp
using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentService
{
    private readonly HttpClient _http;

    public ShipmentService(HttpClient http)
    {
        _http = http;
    }

    public async Task<List<Shipment>> GetShipmentsAsync()
    {
        return await _http.GetFromJsonAsync<List<Shipment>>("api/shipments") ?? [];
    }

    public async Task<Shipment?> TrackShipmentAsync(string trackingNumber)
    {
        var response = await _http.GetAsync($"api/shipments/track/{trackingNumber}");
        if (response.IsSuccessStatusCode)
            return await response.Content.ReadFromJsonAsync<Shipment>();
        return null;
    }

    public async Task CreateShipmentAsync(Shipment shipment)
    {
        await _http.PostAsJsonAsync("api/shipments", shipment);
    }

    public async Task UpdateShipmentAsync(Shipment shipment)
    {
        await _http.PutAsJsonAsync($"api/shipments/{shipment.Id}", shipment);
    }
}
```

## 4. Register HttpClient and ShipmentService

In the CLIENT project's Program.cs (`ShipmentTracker/ShipmentTracker.Client/Program.cs`), add:
```csharp
builder.Services.AddHttpClient<ShipmentService>(client => 
    client.BaseAddress = new Uri(builder.HostEnvironment.BaseAddress));
```
Make sure you add the appropriate using statements.

In the SERVER project's Program.cs, also register the service for prerendering:
```csharp
builder.Services.AddHttpClient<ShipmentService>(client =>
    client.BaseAddress = new Uri("http://localhost:5000"));
```
Actually, to avoid hardcoding, use a scoped service that works during server-side rendering. Let's instead register it like:
```csharp
builder.Services.AddScoped<ShipmentService>();
builder.Services.AddHttpClient<ShipmentService>((sp, client) =>
{
    client.BaseAddress = new Uri("http://localhost:5000");
});
```

Wait, for the server project, we should set up the HttpClient with the correct base address. Let me simplify: let's just use `builder.Services.AddHttpClient<ShipmentService>()` on both and set the base address using IConfiguration or HostEnvironment. For server project, use the app's own URL.

Let me go simpler. For the server project Program.cs, add before `var app = builder.Build();`:
```csharp
builder.Services.AddHttpClient<ShipmentService>(client =>
    client.BaseAddress = new Uri($"http://localhost:{builder.Configuration["ASPNETCORE_HTTP_PORT"] ?? "5000"}"));
```

For the client project Program.cs, add:
```csharp
builder.Services.AddHttpClient<ShipmentService>(client =>
    client.BaseAddress = new Uri(builder.HostEnvironment.BaseAddress));
```

Actually even simpler - the server doesn't really need the HttpClient for ShipmentService since we can call the DB directly during prerendering. But with Auto mode, the component might run on server first. Let's just keep it simple and use HttpClient on both sides.

## 5. Pages

### Dispatcher Dashboard - in Client project
Create `ShipmentTracker/ShipmentTracker.Client/Pages/Dispatcher.razor`:
```razor
@page "/dispatcher"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@inject ShipmentService ShipmentSvc
@rendermode InteractiveAuto

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Dispatcher Dashboard</h1>

<div class="mb-3 row">
    <div class="col-md-4">
        <input class="form-control" placeholder="Filter by destination..." @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="statusFilter">
            <option value="">All Statuses</option>
            @foreach (var status in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@status">@status</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button class="btn btn-primary" @onclick="LoadShipments">Refresh</button>
    </div>
</div>

@if (shipments == null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <p>No shipments found.</p>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Shipped</th>
                <th>ETA</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var s in FilteredShipments)
            {
                <tr>
                    <td>@s.TrackingNumber</td>
                    <td>@s.Origin</td>
                    <td>@s.Destination</td>
                    <td><span class="badge @GetStatusBadge(s.Status)">@s.Status</span></td>
                    <td>@s.ShippedDate.ToString("MMM dd, yyyy")</td>
                    <td>@s.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                    <td>
                        <select class="form-select form-select-sm" value="@s.Status"
                            @onchange="(e) => UpdateStatus(s, e)">
                            @foreach (var status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@status">@status</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Shipment>? shipments;
    private string filterText = "";
    private string statusFilter = "";

    private IEnumerable<Shipment> FilteredShipments => shipments!
        .Where(s => string.IsNullOrEmpty(filterText) || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase))
        .Where(s => string.IsNullOrEmpty(statusFilter) || s.Status.ToString() == statusFilter);

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        shipments = await ShipmentSvc.GetShipmentsAsync();
    }

    private async Task UpdateStatus(Shipment shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            shipment.Status = newStatus;
            await ShipmentSvc.UpdateShipmentAsync(shipment);
        }
    }

    private string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}
```

### Track Shipment - in Client project
Create `ShipmentTracker/ShipmentTracker.Client/Pages/TrackShipment.razor`:
```razor
@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@inject ShipmentService ShipmentSvc
@rendermode InteractiveAuto

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input class="form-control" placeholder="Enter tracking number (e.g., TRK-001234)"
                @bind="trackingNumber" @onkeypress="HandleKeyPress" />
            <button class="btn btn-primary" @onclick="Search" disabled="@isSearching">
                @(isSearching ? "Searching..." : "Track")
            </button>
        </div>
    </div>
</div>

@if (searched && shipment == null)
{
    <div class="alert alert-warning">
        <strong>Not found.</strong> No shipment matches tracking number "@trackingNumber".
    </div>
}
else if (shipment != null)
{
    <div class="card">
        <div class="card-header">
            <h5 class="mb-0">Shipment @shipment.TrackingNumber</h5>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Description</dt>
                        <dd>@shipment.Description</dd>
                        <dt>Origin</dt>
                        <dd>@shipment.Origin</dd>
                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
