        isSearching = true;
        shipment = await ShipmentSvc.TrackShipmentAsync(trackingNumber.Trim());
        searched = true;
        isSearching = false;
    }

    private async Task HandleKeyPress(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
