## 3. Client-side service
Create `ShipmentTracker/ShipmentTracker.Client/Services/ShipmentService.cs`:
```csharp
using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentService
{
    private readonly HttpClient _http;

    public ShipmentService(HttpClient http)
    {
        _http = http;
    }

    public async Task<List<Shipment>> GetShipmentsAsync()
    {
        return await _http.GetFromJsonAsync<List<Shipment>>("api/shipments") ?? [];
    }

    public async Task<Shipment?> TrackShipmentAsync(string trackingNumber)
    {
        var response = await _http.GetAsync($"api/shipments/track/{trackingNumber}");
        if (response.IsSuccessStatusCode)
            return await response.Content.ReadFromJsonAsync<Shipment>();
        return null;
    }

    public async Task CreateShipmentAsync(Shipment shipment)
    {
        await _http.PostAsJsonAsync("api/shipments", shipment);
    }

    public async Task UpdateShipmentAsync(Shipment shipment)
    {
        await _http.PutAsJsonAsync($"api/shipments/{shipment.Id}", shipment);
    }
}
```

