    private async Task Search()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;
        isSearching = true;
        shipment = await ShipmentSvc.TrackShipmentAsync(trackingNumber.Trim());
        searched = true;
        isSearching = false;
    }

